#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>

#include "backprop.h"

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

unsigned int num_threads = 0;
unsigned int num_blocks = 0;

int main( int argc, char** argv) 
{
	setup(argc, argv);
}

void bpnn_train_cuda(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;   

  // CPU computation replacement for GPU parallelism
  printf("Performing CPU computation\n");

  // Layer forward input to hidden
  {
    float sum;
    int j, k;
    net->input_units[0] = 1.0f;
#pragma omp parallel for private(j,k,sum) schedule(static) num_threads(NUM_THREAD)
    for (j = 1; j <= hid; j++) {
      sum = 0.0f;
      for (k = 0; k <= in; k++) {
        sum += net->input_weights[k][j] * net->input_units[k];
      }
      net->hidden_units[j] = 1.0f / (1.0f + expf(-sum));
    }
  }

  // Layer forward hidden to output
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);

  // Calculate output error
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);

  // Calculate hidden error
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);

  // Adjust weights output layer
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

  // Adjust weights hidden layer
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in, net->input_weights, net->input_prev_weights);

  if(eo) *eo = out_err;
  if(eh) *eh = hid_err;
}
